import { NextRequest, NextResponse } from 'next/server'
import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function POST(request: NextRequest) {
  try {
    const cookieStore = await cookies()
    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() { return cookieStore.getAll() },
          setAll(cookiesToSet) {
            try {
              cookiesToSet.forEach(({ name, value, options }) =>
                cookieStore.set(name, value, options)
              )
            } catch (_) {}
          },
        },
      }
    )

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { complaint_id } = await request.json()

    if (!complaint_id) {
      return NextResponse.json({ error: 'Missing complaint_id' }, { status: 400 })
    }

    // Verify ownership and update status
    const { data, error } = await supabase
      .from('complaints')
      .update({ status: 'completed' })
      .eq('id', complaint_id)
      .eq('user_id', user.id) // Ensure only owner can resolve
      .select()

    if (error) {
      console.error('Supabase update error:', error)
      throw error
    }

    if (!data || data.length === 0) {
      return NextResponse.json({ error: 'Complaint not found or ownership mismatch' }, { status: 404 })
    }

    return NextResponse.json({
      success: true,
      status: "completed",
      data: data[0]
    })
  } catch (error) {
    console.error('Error resolving complaint:', error)
    return NextResponse.json(
      { error: 'Failed to resolve complaint' },
      { status: 500 }
    )
  }
}
